import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        String line = br.readLine();
        if (line == null) {
            System.out.print("");
            return;
        }
        line = line.trim();
        if (line.isEmpty()) {
            System.out.print("");
            return;
        }
        int T = Integer.parseInt(line);
        for (int t = 0; t < T; t++) {
            // read N and Wmax
            line = br.readLine();
            if (line == null) break; // no more test cases
            line = line.trim();
            if (line.isEmpty()) { t--; continue; }
            StringTokenizer st = new StringTokenizer(line);
            if (!st.hasMoreTokens()) { t--; continue; }
            int N = Integer.parseInt(st.nextToken());
            if (!st.hasMoreTokens()) {
                // malformed line, stop processing further
                break;
            }
            int Wmax = Integer.parseInt(st.nextToken());
            int[] w = new int[N];
            long[] v = new long[N];
            boolean insufficient = false;
            for (int i = 0; i < N; i++) {
                line = br.readLine();
                if (line == null) { insufficient = true; break; }
                line = line.trim();
                if (line.isEmpty()) { i--; continue; }
                st = new StringTokenizer(line);
                if (!st.hasMoreTokens()) { i--; continue; }
                w[i] = Integer.parseInt(st.nextToken());
                if (!st.hasMoreTokens()) { v[i] = 0; } else { v[i] = Long.parseLong(st.nextToken()); }
            }
            if (insufficient) break; // stop processing further test cases
            long[] dp = new long[Wmax + 1];
            for (int i = 0; i < N; i++) {
                int wi = w[i];
                long vi = v[i];
                for (int cap = Wmax; cap >= wi; cap--) {
                    long cand = dp[cap - wi] + vi;
                    if (cand > dp[cap]) dp[cap] = cand;
                }
            }
            sb.append(dp[Wmax]).append('\n');
        }
        System.out.print(sb.toString());
    }
}

